import React, { useEffect, useRef, useState } from 'react';
import { useParams } from 'react-router-dom';
import { getMovie } from '../services/api';
import videojs from 'video.js';
import 'video.js/dist/video-js.css';

const Player = () => {
  const { id } = useParams();
  const videoRef = useRef(null);
  const playerRef = useRef(null);
  const [movie, setMovie] = useState(null);
  const [loading, setLoading] = useState(true);
  const [currentEpisode, setCurrentEpisode] = useState(null);
  const [showEpisodes, setShowEpisodes] = useState(false);

  useEffect(() => {
    loadMovie();
  }, [id]);

  const loadMovie = async () => {
    try {
      console.log('🎬 Cargando contenido ID:', id);
      const movieData = await getMovie(id);
      console.log('📽️ Contenido cargado:', movieData);
      setMovie(movieData);

      if (movieData.streams && movieData.streams.length > 0) {
        // Si es serie, mostrar episodios sin reproducir
        if (movieData.type === 'series') {
          setShowEpisodes(true);
        } else {
          // Si es película, cargar directamente
          loadVideo(movieData.streams[0].url);
        }
      }
    } catch (error) {
      console.error('❌ Error cargando contenido:', error);
    } finally {
      setLoading(false);
    }
  };

  const loadVideo = (videoSrc) => {
    console.log('🎥 URL del video:', videoSrc);

    if (playerRef.current) {
      playerRef.current.dispose();
      playerRef.current = null;
    }

    if (videoRef.current) {
      playerRef.current = videojs(videoRef.current, {
        controls: true,
        responsive: true,
        fluid: true,
        sources: [{
          src: videoSrc,
          type: 'application/x-mpegURL'
        }]
      });
    }
  };

  const selectEpisode = (episode) => {
    setCurrentEpisode(episode);
    loadVideo(episode.url);
    setShowEpisodes(false);
  };

  const groupEpisodesBySeason = (streams) => {
    const seasons = {};
    streams.forEach(stream => {
      if (!seasons[stream.season]) {
        seasons[stream.season] = [];
      }
      seasons[stream.season].push(stream);
    });
    return seasons;
  };

  useEffect(() => {
    return () => {
      if (playerRef.current) {
        playerRef.current.dispose();
        playerRef.current = null;
      }
    };
  }, []);

  if (loading) return <div className="p-4 text-white">Cargando...</div>;
  if (!movie) return <div className="p-4 text-white">Contenido no encontrado</div>;

  const isSeries = movie.type === 'series';
  const seasons = isSeries ? groupEpisodesBySeason(movie.streams) : null;

  return (
    <div className="bg-black min-h-screen">
      {/* Header */}
      <div className="p-4 flex justify-between items-center">
        <h1 className="text-white text-2xl">
          {movie.title}
          {isSeries && currentEpisode && (
            <span className="text-gray-400 ml-2">
              T{currentEpisode.season}E{currentEpisode.episode} - {currentEpisode.episode_title}
            </span>
          )}
        </h1>

        {isSeries && (
          <button
            onClick={() => setShowEpisodes(!showEpisodes)}
            className="bg-gray-700 hover:bg-gray-600 px-4 py-2 rounded text-white"
          >
            {showEpisodes ? 'Ocultar' : 'Episodios'}
          </button>
        )}
      </div>

      {/* Video Player */}
      {(!isSeries || currentEpisode) && (
        <div className="px-4">
          <video
            ref={videoRef}
            className="video-js vjs-default-skin w-full"
            controls
            preload="auto"
            data-setup="{}"
          />
        </div>
      )}

      {/* Message for series without episode selected */}
      {isSeries && !currentEpisode && (
        <div className="px-4 py-8 text-center">
          <p className="text-gray-400 text-lg">Selecciona un episodio para reproducir</p>
        </div>
      )}

      {/* Episodes List */}
      {isSeries && showEpisodes && (
        <div className="p-4">
          <div className="bg-gray-900 rounded-lg p-4 max-h-96 overflow-y-auto">
            {Object.keys(seasons).sort((a, b) => a - b).map(seasonNum => (
              <div key={seasonNum} className="mb-4">
                <h3 className="text-white text-lg font-semibold mb-2">
                  Temporada {seasonNum}
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-2">
                  {seasons[seasonNum]
                    .sort((a, b) => a.episode - b.episode)
                    .map(episode => (
                    <button
                      key={`${episode.season}-${episode.episode}`}
                      onClick={() => selectEpisode(episode)}
                      className={`p-3 rounded text-left transition-colors ${
                        currentEpisode?.season === episode.season && 
                        currentEpisode?.episode === episode.episode
                          ? 'bg-red-600 text-white'
                          : 'bg-gray-700 hover:bg-gray-600 text-gray-300'
                      }`}
                    >
                      <div className="font-medium">
                        Episodio {episode.episode}
                      </div>
                      <div className="text-sm opacity-75">
                        {episode.episode_title || `Episodio ${episode.episode}`}
                      </div>
                      <div className="text-xs opacity-50">
                        {episode.quality}
                      </div>
                    </button>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default Player;
